        __m512d br=_mm512_add_pd(x2_re,x5_re), bi=_mm512_add_pd(x2_im,x5_im);
        __m512d er=_mm512_sub_pd(x2_re,x5_re), ei=_mm512_sub_pd(x2_im,x5_im);
